    }
  </style>
</head>
<body>
  <div class="card" role="application" aria-label="Real-time String Reverser">
    <header>
      <div class="logo">R</div>
      <div>
        <h1>Real-time String Reverser</h1>
        <p class="lead">Type anything below — the reversed string updates instantly with animated feedback.</p>
      </div>
    </header>

    <div class="controls">
      <div class="input-wrap">
        <label for="inputText">Input</label>
        <input id="inputText" type="text" placeholder="Type here... (supports spaces, emoji, and punctuation)" autocomplete="off" />
      </div>

      <div class="toggles" aria-hidden="true">
        <button id="clearBtn" class="btn" title="Clear input">Clear</button>
        <button id="copyBtn" class="btn" title="Copy reversed">Copy</button>
        <button id="swapMode" class="btn" title="Toggle visual mode">Swap mode</button>
      </div>

      <div class="meta" aria-hidden="true">
        <div class="small">Live</div>
      </div>
    </div>

    <div class="outputCard" aria-live="polite" aria-atomic="true">
      <div id="preview" class="preview" aria-label="Reversed output"></div>
    </div>

    <footer>
      <div class="hint">Character-by-character animation — original on the left, reversed on the right.</div>
      <div class="small">Made with care · No data leaves your device</div>
    </footer>
  </div>

  <script>
    (function(){
      const input = document.getElementById('inputText');
      const preview = document.getElementById('preview');
      const clearBtn = document.getElementById('clearBtn');
      const copyBtn = document.getElementById('copyBtn');
      const swapModeBtn = document.getElementById('swapMode');

      // Mode: 'reverse' - show reversed chars, animating swaps
      // 'mirror' - show reversed but with incoming animation style toggle
      let visualMode = 0;

      // Utility: split string into an array of characters handling surrogate pairs/graphemes reasonably.
      // This uses Intl.Segmenter if available, falling back to [...str] which handles surrogate pairs.
      const splitter = (() => {
        if (typeof Intl !== 'undefined' && Intl.Segmenter) {
          try{
            const seg = new Intl.Segmenter(undefined, {granularity: 'grapheme'});
            return s => Array.from(seg.segment(s), segm => segm.segment);
          }catch(e){}
        }
        return s => Array.from(s);
      })();

      // Manage current nodes to allow transitions
      let lastChars = [];

      function render(text){
        const chars = splitter(text);
        const reversed = [...chars].reverse();

        // We'll perform a simple diff to animate char-level changes.
        // Strategy: create target nodes for reversed array, then compare with lastChars by index.
        // If char equals previous at same index -> keep. If different -> animate in.
        const frag = document.createDocumentFragment();

        reversed.forEach((ch, i) => {
          const span = document.createElement('span');
          span.className = 'char';
          span.dataset.index = i;
          span.textContent = ch === ' ' ? '\u00A0' : ch; // keep visible spacing
          frag.appendChild(span);
        });

        // For a nicer effect, mark chars that persist vs new ones.
        // Clear existing, but animate transitions using requestAnimationFrame ticks.
        // We'll snapshot existing children (old) to allow swap-style animations.
        const old = Array.from(preview.children);

        // Build minimal mapping: for each new char, check if same as old at same position.
        // If same, preserve the old node (avoid reflow), otherwise use the new node and animate.
        const newNodes = [];
        const maxLen = Math.max(old.length, reversed.length);

        for (let i=0;i<maxLen;i++){
          const newCh = reversed[i];
          const oldNode = old[i];
          if (newCh === undefined){
            // old extra -> fade out
            if (oldNode){
              oldNode.classList.add('ghost');
              // schedule removal
              (function(node){
                setTimeout(()=> {
                  if (node.parentNode) node.parentNode.removeChild(node);
                }, 240);
              })(oldNode);
            }
            continue;
          }
          if (oldNode && oldNode.textContent === (newCh === ' ' ? '\u00A0' : newCh)){
            // keep
            oldNode.classList.remove('ghost','in','swap');
            newNodes.push(oldNode);
          }else{
            // create entry node, animate in
            const node = frag.children[i - 0]; // corresponding frag child
            node.classList.add(visualMode === 0 ? 'in' : 'swap');
            node.style.opacity = '0';
            node.style.transform = 'translateY(10px) scale(.96)';
            newNodes.push(node);

            // slight stagger per index
            const delay = Math.min(160, i*20);
            requestAnimationFrame(()=> {
              setTimeout(()=> {
                node.style.transition = 'transform .42s cubic-bezier(.2,.9,.25,1), opacity .28s ease, background .28s ease';
                node.style.opacity = '1';
                node.style.transform = '';
                // clear classes later to keep consistent look
                setTimeout(()=> {
                  node.classList.remove('in','swap');
                }, 420);
              }, delay);
            });
          }
        }

        // Replace preview content with newNodes in order
        preview.innerHTML = '';
        newNodes.forEach(n => preview.appendChild(n));

        // Keep lastChars for next diff
        lastChars = reversed.slice();
      }

      // Input handling: immediate render, but keep micro-batching for quick typing
      let raf = null;
      function handleInput(){
        const v = input.value;
        if (raf) cancelAnimationFrame(raf);
        raf = requestAnimationFrame(()=> {
          render(v);
          raf = null;
        });
      }

      input.addEventListener('input', handleInput);

      // Buttons
      clearBtn.addEventListener('click', ()=>{
        input.value = '';
        handleInput();
        input.focus();
      });

      copyBtn.addEventListener('click', async ()=>{
        // copy the reversed plain text
        const chars = splitter(input.value);
        const reversed = chars.reverse().join('');
        try{
          await navigator.clipboard.writeText(reversed);
          copyBtn.textContent = 'Copied';
          copyBtn.classList.add('primary');
          setTimeout(()=>{ copyBtn.textContent='Copy'; copyBtn.classList.remove('primary'); }, 900);
        }catch(e){
          // fallback: select and execCopy
          try{
            const ta = document.createElement('textarea');
            ta.value = reversed;
            document.body.appendChild(ta);
            ta.select();
            document.execCommand('copy');
            ta.remove();
            copyBtn.textContent = 'Copied';
            copyBtn.classList.add('primary');
            setTimeout(()=>{ copyBtn.textContent='Copy'; copyBtn.classList.remove('primary'); }, 900);
          }catch(e2){
            alert('Copy failed — please copy manually.');
          }
        }
      });

      swapModeBtn.addEventListener('click', ()=>{
        visualMode = (visualMode + 1) % 2;
        // tiny UI hint
        swapModeBtn.textContent = visualMode === 0 ? 'Swap mode' : 'Glow mode';
        // re-render to apply mode classes
        handleInput();
      });

      // Init with empty
      render('');

      // Accessibility: pressing Escape clears input
      input.addEventListener('keydown', (e)=>{
        if (e.key === 'Escape'){
          input.value = '';
          handleInput();
        }
      });

      // Optional: paste handling to keep cursor position but trigger render
      input.addEventListener('paste', (e)=>{
        setTimeout(handleInput, 0);
      });

    })();
  </script>
</body>
</html>

