<script>
(function(){
  const src = document.getElementById('source');
  const result = document.getElementById('result');
  const len = document.getElementById('len');
  const meta = document.getElementById('meta');
  const perf = document.getElementById('perf');
  const status = document.getElementById('status');
  const clearBtn = document.getElementById('clear');
  const copyBtn = document.getElementById('copy');
  const toggleSlow = document.getElementById('toggleSlow');
  const shuffle = document.getElementById('shuffle');

  let slowMode = false;
  let lastText = '';
  let animId = 0;

  // Helper: iterate grapheme clusters to handle emojis and combining marks properly
  function splitGraphemes(str){
    // Use Intl.Segmenter if available for grapheme clusters
    if (typeof Intl !== 'undefined' && Intl.Segmenter) {
      const seg = new Intl.Segmenter(undefined, { granularity: 'grapheme' });
      return Array.from(seg.segment(str), s => s.segment);
    }
    // Fallback naive split that handles surrogate pairs reasonably
    return Array.from(str);
  }

  function reverseGraphemes(str){
    return splitGraphemes(str).reverse();
  }

  // animate update by diffing old and new arrays
  function renderReversed(newText){
    const start = performance.now();
    animId++;
    const currentAnim = animId;
    const newArr = reverseGraphemes(newText);
    const prevNodes = Array.from(result.children).map(n => n.dataset.ch);
    const prevArr = prevNodes.slice(); // array of strings

    len.textContent = newText.length + ' chars';

    // compute simple diff: we'll try to preserve characters that match at same index;
    // others will be removed/inserted with animations. This gives visible per-char moves.
    // For better visual effect, we'll clear and animate each entering char with slight delays.

    // mark all existing nodes as leaving by default
    for (const node of result.children){
      node.classList.remove('entering');
      node.classList.add('leaving');
    }

    // Clear after short delay to allow popOut animation, but if slowMode stepping, wait for click
    const doReplace = () => {
      // If another update started, abort this replacement
      if (currentAnim !== animId) return;
      // remove all children
      while (result.firstChild) result.removeChild(result.firstChild);

      // create new nodes in order (reversed order already in newArr)
      newArr.forEach((ch, i) => {
        const div = document.createElement('div');
        div.className = 'char entering';
        div.dataset.ch = ch;
        div.textContent = ch === ' ' ? '\u00A0' : ch;
        // stagger animation slightly for a wave
        div.style.animationDelay = (i * 18) + 'ms';
        result.appendChild(div);
      });

      // if empty, show placeholder blanks
      if (newArr.length === 0){
        const ph = document.createElement('div');
        ph.className = 'char blank';
        ph.textContent = '—';
        result.appendChild(ph);
      }

      const elapsed = performance.now() - start;
      perf.textContent = Math.round(elapsed) + 'ms';
      meta.textContent = `${newArr.length} characters reversed`;
      status.textContent = 'Reversed Preview';

      // focus highlight effect on first char
      if (result.firstChild){
        result.firstChild.style.boxShadow = '0 10px 30px rgba(125,211,252,0.12)';
        setTimeout(()=> {
          if (result.firstChild) result.firstChild.style.boxShadow = '';
        }, 420);
      }
    };

    if (slowMode && prevArr.join('') !== newArr.join('')){
      // In slow mode, step through: remove existing, then insert one char at a time with user clicking toggleSlow
      status.textContent = 'Sticky Step — click "Sticky Step" to step or toggle off';
      // clear existing immediately:
      while (result.firstChild) result.removeChild(result.firstChild);

      // create placeholders
      const placeholders = newArr.map(() => {
        const ph = document.createElement('div');
        ph.className = 'char blank';
        ph.textContent = '\u2022'; // dot
        return ph;
      });
      placeholders.forEach(p => result.appendChild(p));

      // set up stepping state
      let idx = 0;
      const stepOnce = () => {
        if (currentAnim !== animId) return;
        if (idx >= newArr.length) {
          meta.textContent = `${newArr.length} characters reversed`;
          perf.textContent = Math.round(performance.now() - start) + 'ms';
          return;
        }
        const ch = newArr[idx];
        const node = placeholders[idx];
        node.className = 'char entering';
        node.dataset.ch = ch;
        node.textContent = ch === ' ' ? '\u00A0' : ch;
        idx++;
      };

      // attach a one-time click to toggleSlow button to step; also allow clicking result area
      const stepHandler = (e) => { stepOnce(); };
      toggleSlow.addEventListener('click', stepHandler, { once: false });
      result.addEventListener('click', stepHandler, { once: false });

      // also auto step a few to feel alive
      const autoStep = () => {
        if (currentAnim !== animId) return;
        if (idx < newArr.length) {
          stepOnce();
          setTimeout(autoStep, 160 + Math.random()*160);
        }
      };
      autoStep();

      // remove listeners when animation superseded
      setTimeout(()=> {
        toggleSlow.removeEventListener('click', stepHandler);
        result.removeEventListener('click', stepHandler);
      }, 20000);

      perf.textContent = Math.round(performance.now() - start) + 'ms';
      meta.textContent = `Step mode: ${newArr.length} chars`;
    } else {
      // Normal fast replacement with brief out animation
      setTimeout(doReplace, 120);
    }
  }

  // input handler with slight debounce for nice feel
  let tick;
  src.addEventListener('input', (e) => {
    clearTimeout(tick);
    const text = src.value;
    len.textContent = text.length + ' chars';
    // immediate lightweight transform for small strings
    if (text.length < 200){
      // small delay to allow natural typing
      tick = setTimeout(()=> renderReversed(text), 60);
    } else {
      // for long text, do a microtask to keep UI responsive
      tick = setTimeout(()=> renderReversed(text), 10);
    }
  });

  // buttons
  clearBtn.addEventListener('click', () => {
    src.value = '';
    src.focus();
    renderReversed('');
  });

  copyBtn.addEventListener('click', async () => {
    const chars = Array.from(result.children).map(n => n.dataset.ch || n.textContent || '');
    const txt = chars.join('');
    try{
      await navigator.clipboard.writeText(txt);
      status.textContent = 'Copied reversed to clipboard';
      setTimeout(()=> status.textContent = 'Reversed Preview', 1200);
    }catch(err){
      status.textContent = 'Copy failed — select and copy manually';
      setTimeout(()=> status.textContent = 'Reversed Preview', 1200);
    }
  });

  toggleSlow.addEventListener('click', () => {
    slowMode = !slowMode;
    toggleSlow.classList.toggle('primary', slowMode);
    toggleSlow.textContent = slowMode ? 'Sticky Step (ON)' : 'Sticky Step';
    // re-render to apply mode
    renderReversed(src.value);
  });

  shuffle.addEventListener('click', () => {
    const demos = [
      "Hello, world!",
      "Emoji test: 😀👍🏽✨",
      "The quick brown fox jumps over the lazy dog.",
      "12345 abcde 67890",
      "こんにちは、世界！",
      "Line 1\nLine 2\nLine 3",
      "function reverse(s) { return s.split('').reverse().join('') }",
      "Combining: e\u0301 and é look similar"
    ];
    const pick = demos[Math.floor(Math.random()*demos.length)];
    src.value = pick;
    src.focus();
    // put caret at end
    src.setSelectionRange(pick.length, pick.length);
    renderReversed(pick);
  });

  // keyboard: pressing Enter will toggle slow mode quickly
  src.addEventListener('keydown', (e) => {
    if (e.key === 'Enter' && !e.shiftKey){
      e.preventDefault();
      slowMode = !slowMode;
      toggleSlow.classList.toggle('primary', slowMode);
      toggleSlow.textContent = slowMode ? 'Sticky Step (ON)' : 'Sticky Step';
      renderReversed(src.value);
    }
  });

  // initial render empty
  renderReversed('');

  // accessibility: allow pressing space on result to copy
  result.addEventListener('keydown', async (e) => {
    if (e.key === ' '){
      e.preventDefault();
      copyBtn.click();
    }
  });

  // scattering micro interactions: when user types fast, add a little pulse on result
  let lastPulse = 0;
  src.addEventListener('input', () => {
    const now = Date.now();
    if (now - lastPulse < 90) return;
    lastPulse = now;
    result.animate([
      { transform: 'scale(1)' },
      { transform: 'scale(1.01)' },
      { transform: 'scale(1)' }
    ], { duration: 260, easing: 'cubic-bezier(.2,.9,.27,1)' });
  });

})();
</script>
