  <script>
    (function(){
      const input = document.getElementById('input');
      const charsWrap = document.getElementById('chars');
      const emptyHint = document.querySelector('.empty-hint');
      const countEl = document.getElementById('count');
      const clearBtn = document.getElementById('clearBtn');
      const copyBtn = document.getElementById('copyBtn');

      // Helper to split by Unicode grapheme clusters (better for emoji & combined chars)
      // Small, dependency-free implementation using Intl.Segmenter if available, otherwise fallback to Array.from
      const splitter = (s) => {
        if (typeof Intl !== 'undefined' && Intl.Segmenter) {
          try {
            const seg = new Intl.Segmenter(undefined, {granularity:'grapheme'});
            return Array.from(seg.segment(s), s => s.segment);
          } catch(e){}
        }
        return Array.from(s);
      };

      let lastChars = [];

      function renderReversed(text){
        const arr = splitter(text);
        const reversed = arr.slice().reverse();
        countEl.textContent = arr.length;

        // If empty
        if (reversed.length === 0){
          charsWrap.style.display = 'none';
          emptyHint.style.display = 'block';
          lastChars = [];
          return;
        } else {
          emptyHint.style.display = 'none';
          charsWrap.style.display = 'flex';
        }

        // Reconcile old vs new to animate changes per character
        const maxLen = Math.max(lastChars.length, reversed.length);
        const newChildren = [];

        for (let i = 0; i < reversed.length; i++){
          const ch = reversed[i];
          // Reuse existing element if same char at same index
          let el = charsWrap.children[i];
          const shouldReuse = el && el.dataset && el.dataset.char === ch;
          if (shouldReuse){
            newChildren.push(el);
          } else {
            // Create new element for this char
            el = document.createElement('span');
            el.className = 'char';
            el.textContent = ch;
            el.dataset.char = ch;
            // animation: staggered flip for new or changed chars
            // add a small timeout to create stagger
            (function(e, idx){
              e.classList.add('animate-flip');
              // random slight hue per char via CSS filter
              const hue = 185 + (idx * 23 % 70);
              e.style.filter = `drop-shadow(0 8px 16px rgba(2,6,23,0.45))`;
              // remove animation class after done
              setTimeout(()=> e.classList.remove('animate-flip'), 600);
            })(el, i);
            newChildren.push(el);
          }
        }

        // For any leftover old elements beyond new length, fade them out
        for (let i = reversed.length; i < lastChars.length; i++){
          const old = charsWrap.children[i];
          if (old){
            old.classList.add('fade-out');
            // remove after animation
            setTimeout(()=> {
              if (old && old.parentNode) old.parentNode.removeChild(old);
            }, 400);
          }
        }

        // Rebuild the DOM to match order
        charsWrap.innerHTML = '';
        newChildren.forEach((c, idx) => {
          // slight stagger for pop-in if created recently
          if (!c.dataset.inited){
            c.dataset.inited = '1';
            c.classList.add('animate-in');
            // stagger timing
            c.style.animationDelay = (idx * 28) + 'ms';
            setTimeout(()=> {
              c.classList.remove('animate-in');
              c.style.animationDelay = '';
            }, 520 + idx * 28);
          }
          charsWrap.appendChild(c);
        });

        // store last
        lastChars = reversed.slice();
      }

      // Debounce visual updates slightly to allow fast typing but keep per-update feedback
      let raf = null;
      input.addEventListener('input', () => {
        if (raf) cancelAnimationFrame(raf);
        raf = requestAnimationFrame(() => {
          renderReversed(input.value);
        });
      });

      // initial
      renderReversed('');

      clearBtn.addEventListener('click', () => {
        input.value = '';
        input.focus();
        renderReversed('');
      });

      copyBtn.addEventListener('click', async () => {
        const text = (function(){
          // build reversed string
          const s = input.value || '';
          return splitter(s).reverse().join('');
        })();
        try {
          await navigator.clipboard.writeText(text);
          copyBtn.textContent = 'Copied';
          setTimeout(()=> copyBtn.textContent = 'Copy', 1100);
        } catch (e){
          // fallback: select and execCommand (may be deprecated)
          const ta = document.createElement('textarea');
          ta.value = text;
          ta.style.position = 'fixed';
          ta.style.opacity = '0';
          document.body.appendChild(ta);
          ta.select();
          try { document.execCommand('copy'); copyBtn.textContent = 'Copied'; }
          catch(e2){ alert('Copy failed — please copy manually: ' + text); }
          document.body.removeChild(ta);
          setTimeout(()=> copyBtn.textContent = 'Copy', 1100);
        }
      });

      // keyboard shortcut: Esc to clear
      input.addEventListener('keydown', (e) => {
        if (e.key === 'Escape') {
          input.value = '';
          renderReversed('');
        }
      });

      // accessibility: focus input on container click
      document.querySelector('.container').addEventListener('click', (e) => {
        if (!e.target.closest('input')) input.focus();
      });

    })();
  </script>
